            returnValues = new ArrayList<>(returnValueSize);
            for (int i = 0; i < returnValueSize; i++) {
                returnValues.add(Symbol.fromStream(in));
            }
        } else {
            returnValues = List.of();
        }
    } else {
        returnValues = List.of();
        outputs = List.of();
